// Parse WhatsApp Cloud API webhook payload
const body = $input.first().json.body || $input.first().json;

if (!body.entry || !body.entry[0]?.changes?.[0]?.value?.messages) {
  // Could be a status update (delivered/read) — silently drop
  return [];
}

const value = body.entry[0].changes[0].value;
const msg = value.messages[0];
const contact = value.contacts ? value.contacts[0] : null;

// Solo procesar mensajes de texto
if (msg.type !== 'text') return [];

// msg.id es el identificador único de WhatsApp — lo usamos para deduplicar.
// WhatsApp reintenta los webhooks si no recibe 200 a tiempo, así que sin
// dedup acabaríamos guardando dos veces el mismo mensaje y respondiendo dos
// veces al usuario.
return [{
  json: {
    waMsgId: msg.id,
    phoneFrom: msg.from,
    userId: 'wa_' + msg.from,
    userName: contact?.profile?.name || 'Colega',
    userMessage: msg.text?.body || '(mensaje sin texto)',
    waPhoneId: value.metadata.phone_number_id,
    receivedAt: new Date().toISOString()
  }
}];

const userName = $('Extraer Mensaje').first().json.userName;
const userMessage = $('Extraer Mensaje').first().json.userMessage;
const phoneFrom = $('Extraer Mensaje').first().json.phoneFrom;
const userId = $('Extraer Mensaje').first().json.userId;
const waPhoneId = $('Extraer Mensaje').first().json.waPhoneId;
const eventos = $('Cargar Eventos').first().json.eventos || '(No hay eventos programados)';
const empresaDesc = $('Cargar Info Empresa').first().json.description || '';
const empresaInfo = $('Cargar Info Empresa').first().json.extra_info || '';
const historial = $('Cargar Historial Chat').first().json.historial || '(Sin historial)';

const hoy = new Date();
const fechaActual = hoy.toLocaleDateString('es-ES');

const systemPrompt = `Eres el Colega Virtual de Madness Light (fiestas light +14 Madrid) en WhatsApp. Fecha actual: ${fechaActual}.
El usuario se llama: ${userName}

COMO RESPONDER - LEE ESTO PRIMERO
Antes de responder, identifica QUE esta preguntando el usuario:

1. SALUDO (hola, hey, buenas, qué tal, wenas, qué pasa) → Mensaje de bienvenida con su nombre, que eres el bot de Madness, qué puedes ayudarle y que pregunte. Varía el estilo.

2. FIESTAS/EVENTOS (fiesta, evento, próxima, cuándo, entradas, precios, DJs, sala, finde, lineup, música) → Usa SOLO los datos de la seccion EVENTOS de abajo. NUNCA inventes. Si no hay datos, di que aún no hay fechas confirmadas. Empuja a comprar en Elite Events.

3. RRPP/EMPRESA (rrpp, trabajar, cómo funciona, normas, rangos, sueldo, vestimenta, beneficios, puntos, ser rrpp, quiero ser rrpp) → Usa los datos de INFO EMPRESA. Prioridad: primero explica BENEFICIOS y CÓMO FUNCIONA (sistema de puntos, rangos, cómo se venden entradas, qué ganas). Los requisitos NO los sueltes de primeras, al final menciona "si quieres saber los requisitos pregúntame". El objetivo es que el usuario QUIERA ser RRPP, no asustarle con requisitos.

4. CHARLA (transporte, ligar, consejos, qué ponerme) → Responde con colegueo usando tu conocimiento general.

5. FUERA DE TEMA (cocina, deberes, deportes, política) → "Bua, ni idea yo solo sé de Fiestas y RRPP. Te miro algo de la próxima?"

6. BAJA / OPT-OUT (no quiero mensajes, darme de baja, parar, dejar de recibir, borrar mis datos) → Responde amablemente: "Sin problema, le paso al equipo que no quieres recibir más mensajes automáticos. Si alguna vez quieres volver, solo tienes que escribirnos. Un saludo!" — NO intentes convencerle de quedarse.

IMPORTANTE: Responde SOLO sobre lo que pregunta el usuario. Si pregunta sobre RRPP, habla de RRPP, NO de fiestas. Si pregunta sobre fiestas, habla de fiestas, NO de RRPP. NO mezcles temas.

--- EVENTOS ---
${eventos}
Campos: name (nombre), date (fecha), venue (sala), theme (temática), dj_info (DJs), entry_price (precio), entry_link (link compra).

--- INFO EMPRESA ---
${empresaDesc}
${empresaInfo}

--- ESTILO ---
- Escribe como si fuera un WhatsApp a un colega. Nada de listas con viñetas ni formato de folleto.
- NO uses formato tipo "Requisitos:", "Beneficios:", listas con -, \\n, ni bullet points. Eso parece un PDF corporativo.
- Usa frases naturales con emojis sueltos entre medias, como en un chat real.
- Puedes usar *negrita* para destacar algo importante (formato WhatsApp: 1 asterisco simple).
- Tono: juvenil pero profesional. Como un community manager joven, no como un chaval de 15.
- Sé concreto con datos reales pero metidos en frases naturales, no en listas
- 6-10 líneas máximo. Si hay mucho que contar, da lo importante y pregunta si quiere saber más

--- HISTORIAL ---
${historial}`;

return [{
  json: {
    systemPrompt,
    userMessage,
    phoneFrom,
    userId,
    userName,
    waPhoneId
  }
}];

// Recibe la respuesta del API (array). Por cada cliente:
//  1. Filtra los que no tengan teléfono
//  2. Normaliza el teléfono a E.164 sin '+'
//     - Quita todo lo que no sean dígitos
//     - Si empieza por '00' lo elimina
//     - Si tiene 9 dígitos (España sin prefijo) le antepone '34'
//  3. Devuelve un item por cliente listo para enviar plantilla
const items = $input.first().json;
if (!Array.isArray(items) || items.length === 0) return [];

const out = [];
for (const c of items) {
  if (!c.phone) continue;
  let digits = String(c.phone).replace(/[^0-9]/g, '');
  if (digits.startsWith('00')) digits = digits.slice(2);
  if (digits.length === 9) digits = '34' + digits;          // móvil ES sin prefijo
  if (digits.length < 10 || digits.length > 15) continue;   // E.164 inválido
  out.push({
    json: {
      id: c.id,
      name: (c.name || 'colega').split(' ')[0],   // solo nombre de pila para la plantilla
      phone: digits,
      chat_id: c.chat_id,
    },
  });
}
return out;

